"use client";

import { useCreateBuyback } from "@/shared/api/query-hooks/use-buyback";
import { APP_ROUTES } from "@/shared/config/app-routes";
import { ASSET_EXTRA_KEYS } from "@/shared/constants/asset";
import { BuybackType } from "@/shared/types/buyback.types";
import { Button } from "@/shared/ui/shadcn/button";
import { Stepper } from "@/shared/ui/shadcn/stepper";
import {
  BuybackCreateStep1Form,
  type Step1FormData,
} from "@/widgets/buyback-create-step1-form-new";
import { BuybackCreateSuccess } from "@/widgets/buyback-create-success-new";
import { BuybackCreateSummary } from "@/widgets/buyback-create-summary-new";
import {
  BuybackUploadForm,
  type UploadedFile,
} from "@/widgets/buyback-upload-form-new";
import {
  ArrowRightIcon,
  CheckIcon,
  IdCardIcon,
  InfoIcon,
  Loader2,
} from "lucide-react";
import { useSession } from "next-auth/react";
import Image from "next/image";
import { useRouter } from "next/navigation";
import type { FC } from "react";
import { useEffect, useState } from "react";

const WIZARD_DRAFT_KEY = "buyback_wizard_draft";

interface WizardDraft {
  formData: Step1FormData;
  uploadedFiles: Record<string, UploadedFile>;
}

export const BuybackCreateWizard: FC = () => {
  const router = useRouter();
  const { status } = useSession();
  const [currentStep, setCurrentStep] = useState(1);
  const [isMobile, setIsMobile] = useState(false);

  const [uploadedFiles, setUploadedFiles] = useState<
    Record<string, UploadedFile>
  >({});

  const [formData, setFormData] = useState<Step1FormData>({
    type: BuybackType.Buyback,
    categoryId: "",
    brandId: "",
    modelId: "",
    condition: "",
    year: new Date().getFullYear(),
    modelNumber: "",
    extras: [],
  });

  const { mutateAsync: createBuyback, isPending } = useCreateBuyback();

  // Restore draft after login redirect: if user was redirected to sign-in with
  // a saved draft, restore it and jump to step 3 once authenticated.
  useEffect(() => {
    if (status === "loading") return;
    if (status !== "authenticated") return;

    try {
      const saved = localStorage.getItem(WIZARD_DRAFT_KEY);
      if (!saved) return;

      const draft = JSON.parse(saved) as WizardDraft;
      setFormData(draft.formData);
      setUploadedFiles(draft.uploadedFiles);
      setCurrentStep(3);
      localStorage.removeItem(WIZARD_DRAFT_KEY);
    } catch {
      localStorage.removeItem(WIZARD_DRAFT_KEY);
    }
  }, [status]);

  useEffect(() => {
    const checkMobile = () => setIsMobile(window.innerWidth < 768);
    checkMobile();
    window.addEventListener("resize", checkMobile);
    return () => window.removeEventListener("resize", checkMobile);
  }, []);

  const isStep1Valid = !!(
    formData.categoryId &&
    formData.brandId &&
    formData.modelId &&
    formData.condition
  );
  const isStep2Valid = Object.keys(uploadedFiles).length > 0;

  const canContinue =
    {
      1: isStep1Valid,
      2: isStep2Valid,
      3: true,
    }[currentStep as 1 | 2 | 3] ?? false;

  async function handleSubmit() {
    if (status !== "authenticated") {
      const draft: WizardDraft = { formData, uploadedFiles };
      localStorage.setItem(WIZARD_DRAFT_KEY, JSON.stringify(draft));
      const callbackUrl = encodeURIComponent(
        APP_ROUTES.BUYBACK_REQUESTS.CREATE
      );
      router.push(`${APP_ROUTES.AUTH.SIGN_IN}?callbackUrl=${callbackUrl}`);
      return;
    }

    const photos = Object.values(uploadedFiles).map((file) => file.fileId);
    const extras = {
      originalBox: formData.extras.includes(ASSET_EXTRA_KEYS.ORIGINAL_BOX),
      ownershipDocs: formData.extras.includes(
        ASSET_EXTRA_KEYS.OWNERSHIP_CERTIFICATE
      ),
      authCert: formData.extras.includes(
        ASSET_EXTRA_KEYS.AUTHENTICATION_CERTIFICATE
      ),
    };

    const payload = {
      type: formData.type,
      asset: {
        year: formData.year,
        condition: formData.condition,
        categoryFields: {},
        categoryId: formData.categoryId,
        brandId: formData.brandId,
        modelId: formData.modelId,
        modelNumber: formData.modelNumber || "N/A",
        extras,
        photos,
        meta: { photos: { order: photos, main: photos[0] } },
      },
    };

    try {
      await createBuyback(payload);
      setCurrentStep(4);
      window.scrollTo({ top: 0, behavior: "instant" });
    } catch (error) {
      console.error("Failed to create buyback:", error);
    }
  }

  const handleReset = () => {
    localStorage.removeItem(WIZARD_DRAFT_KEY);
    setFormData({
      type: BuybackType.Buyback,
      categoryId: "",
      brandId: "",
      modelId: "",
      condition: "",
      year: new Date().getFullYear(),
      modelNumber: "",
      extras: [],
    });
    setUploadedFiles({});
    setCurrentStep(1);
  };

  const handleNext = () => {
    if (currentStep < 3) {
      setCurrentStep((prev) => prev + 1);
      document.documentElement.scrollTo({ top: 0, behavior: "instant" });
    } else {
      handleSubmit();
    }
  };

  const activeStepperStep = currentStep > 3 ? 3 : currentStep;

  return (
    <div className="relative min-h-screen w-full">
      <div className="-z-50 pointer-events-none fixed inset-0 h-full w-full">
        <Image
          alt="Background"
          className="object-cover object-center"
          fill
          priority
          src="/new-design-images/create-buyback-bg.webp"
        />
        <div
          className="absolute inset-0"
          style={{
            background:
              "linear-gradient(to bottom, #EDE9E3 0%, rgba(237, 233, 227, 0) 50%, #EDE9E3 100%)",
          }}
        />
      </div>

      <div className="new-design relative z-10 w-full bg-inherit px-4 py-5">
        <div className="mx-auto w-full max-w-[600px] space-y-[25px]">
          {currentStep < 4 && (
            <div className="flex flex-col items-center gap-1">
              <h1 className="text-center font-extralight font-new-serif text-2xl md:text-3xl">
                Request a Quote for Your Item
              </h1>
              <p className="text-center font-400 font-new-sans text-sm md:text-[16px]">
                Complete this simple form to receive a quote. Our team will
                review your submission and provide an offer in minutes.
              </p>
            </div>
          )}

          <Stepper
            className="!text-sm"
            currentStep={activeStepperStep}
            steps={[
              { label: isMobile ? "Details" : "Item Details" },
              { label: isMobile ? "Photos" : "Item Photos" },
              { label: isMobile ? "Submit" : "Offer Submission" },
            ]}
          />

          {currentStep === 4 ? (
            <BuybackCreateSuccess onReset={handleReset} />
          ) : (
            <>
              <div className="mt-4 w-full rounded-[--radius] border border-border bg-background px-4 py-6 shadow-lg md:px-6 md:py-8">
                {currentStep === 1 && (
                  <BuybackCreateStep1Form
                    formData={formData}
                    setFormData={setFormData}
                  />
                )}

                {currentStep === 2 && (
                  <BuybackUploadForm
                    category={formData.categoryId}
                    files={uploadedFiles}
                    isSubmitting={isPending}
                    setFiles={setUploadedFiles}
                  />
                )}

                {currentStep === 3 && (
                  <BuybackCreateSummary
                    formData={formData}
                    uploadedFiles={uploadedFiles}
                  />
                )}
              </div>

              {currentStep === 3 && (
                <div className="space-y-3 font-new-sans">
                  <div className="flex gap-3 rounded-[--radius] border border-border bg-background p-4">
                    <InfoIcon className="mt-0.5 h-5 w-5 shrink-0" />
                    <div className="space-y-1">
                      <h4 className="font-bold text-sm">What happens next?</h4>
                      <p className="font-new-sans text-sm leading-relaxed">
                        Once you submit your offer request our team of experts
                        will review its details to estimate an initial offer.
                        Then you can decide to move forward with the process.
                      </p>
                    </div>
                  </div>

                  <div className="flex gap-3 rounded-[--radius] border border-border bg-background p-4">
                    <IdCardIcon size={20} />
                    <div className="space-y-1">
                      <h4 className="font-bold text-sm">
                        Account Verification Pending
                      </h4>
                      <p className="font-new-sans text-sm leading-[150%]">
                        Account verification will be needed in the future in
                        order to get your deposit.
                      </p>
                    </div>
                  </div>
                </div>
              )}

              <div className="flex w-full items-center justify-between py-4">
                <Button
                  onClick={() =>
                    currentStep === 1
                      ? router.back()
                      : setCurrentStep((p) => p - 1)
                  }
                  variant="simple"
                >
                  {currentStep === 1 ? "Cancel" : "Back"}
                </Button>

                <Button
                  className="flex h-[48px] items-center gap-2 rounded-[4px] font-normal text-sm"
                  disabled={isPending || !canContinue}
                  onClick={handleNext}
                >
                  {isPending ? (
                    <Loader2 className="h-5 w-5 animate-spin" />
                  ) : (
                    <>
                      <span>
                        {currentStep === 1 && "Continue to Images"}
                        {currentStep === 2 && "Continue to Preview"}
                        {currentStep === 3 && "Submit Offer"}
                      </span>
                      {currentStep < 3 ? (
                        <ArrowRightIcon className="h-5 w-5" />
                      ) : (
                        <CheckIcon className="h-5 w-5" />
                      )}
                    </>
                  )}
                </Button>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

