16	
17	export const PUBLIC_PAGES = [
18	  APP_ROUTES.APP.PRICING,
19	  APP_ROUTES.APP.ABOUT,
20	  APP_ROUTES.APP.CONTACT,
21	  APP_ROUTES.APP.FAQ,
22	  APP_ROUTES.APP.POLICY,
23	  APP_ROUTES.APP.TERMS,
24	  APP_ROUTES.TICKETS.CREATE,
25	  APP_ROUTES.SUPPORT,
26	  "/services",
27	  APP_ROUTES.BUYBACK_REQUESTS.CREATE,
28	];
29	
