31	export const PROTECTED_SELLER_AND_BIDDER_PAGES = [
32	  APP_ROUTES.PROFILE,
33	  APP_ROUTES.WALLET.ROOT,
34	  APP_ROUTES.SETTINGS,
35	  APP_ROUTES.APP.MY_DEALS,
