40	export function isAdminUser(profile?: Profile | null): boolean {
41	  if (!profile) return false;
42	
43	  return profile.roles.some(
44	    (role) => role === UserRole.ADMIN || role === UserRole.SUPER_ADMIN,
45	  );
46	}
47	
48	export function isAuthenticatorUser(profile?: Profile | null): boolean {
49	  if (!profile) return false;
50	
51	  return profile.roles.some((role) => role === UserRole.AUTHENTICATOR);
52	}
53	
54	export function isRegularUser(profile?: Profile | null): boolean {
55	  if (!profile) return false;
56	
57	  return profile.roles.some(
58	    (role) => role === UserRole.SELLER,
59	    // || role === UserRole.BIDDER // Not in MVP
60	  );
61	}
62	
63	export function hasAdminPermissions(profile?: Profile | null): boolean {
64	  if (!profile) return false;
65	
66	  return !!profile.admin && profile.admin.permissions.length > 0;
67	}
