import type { Profile } from "@/entities/profile";
import { UserRole } from "@/shared/types/auth.types";

import { APP_ROUTES } from "./app-routes";
import { AUTH_ROUTES_LIST } from "./auth-constants";

export const ADMIN_ROLES = [UserRole.ADMIN, UserRole.SUPER_ADMIN] as const;

export const REGULAR_USER_ROLES = [
  UserRole.SELLER,
  // UserRole.BIDDER // Not in MVP
] as const;

export const ADMIN_ROUTE_PREFIX = APP_ROUTES.ADMIN.ROOT;
export const AUTHENTICATOR_ROUTE_PREFIX = "/authenticator";

export const PUBLIC_PAGES = [
  APP_ROUTES.APP.PRICING,
  APP_ROUTES.APP.ABOUT,
  APP_ROUTES.APP.CONTACT,
  APP_ROUTES.APP.FAQ,
  APP_ROUTES.APP.POLICY,
  APP_ROUTES.APP.TERMS,
  APP_ROUTES.TICKETS.CREATE,
  APP_ROUTES.SUPPORT,
  "/services",
  APP_ROUTES.BUYBACK_REQUESTS.CREATE,
];

// Previously PROTECTED_SELLER_AND_BIDDER_PAGES - now seller only for MVP
export const PROTECTED_SELLER_AND_BIDDER_PAGES = [
  APP_ROUTES.PROFILE,
  APP_ROUTES.WALLET.ROOT,
  APP_ROUTES.SETTINGS,
  APP_ROUTES.APP.MY_DEALS,
  APP_ROUTES.BUYBACK_REQUESTS.LIST,
  APP_ROUTES.BUYBACKS.LIST,
];

export function isAdminUser(profile?: Profile | null): boolean {
  if (!profile) return false;

  return profile.roles.some(
    (role) => role === UserRole.ADMIN || role === UserRole.SUPER_ADMIN,
  );
}

export function isAuthenticatorUser(profile?: Profile | null): boolean {
  if (!profile) return false;

  return profile.roles.some((role) => role === UserRole.AUTHENTICATOR);
}

export function isRegularUser(profile?: Profile | null): boolean {
  if (!profile) return false;

  return profile.roles.some(
    (role) => role === UserRole.SELLER,
    // || role === UserRole.BIDDER // Not in MVP
  );
}

export function hasAdminPermissions(profile?: Profile | null): boolean {
  if (!profile) return false;

  return !!profile.admin && profile.admin.permissions.length > 0;
}

export function isAdminRoute(pathname: string): boolean {
  return pathname.startsWith(ADMIN_ROUTE_PREFIX);
}

export function isAuthenticatorRoute(pathname: string): boolean {
  return (
    pathname === AUTHENTICATOR_ROUTE_PREFIX ||
    pathname.startsWith(`${AUTHENTICATOR_ROUTE_PREFIX}/`)
  );
}

export function isProtectedRoute(pathname: string): boolean {
  return PROTECTED_SELLER_AND_BIDDER_PAGES.some((path) =>
    pathname.startsWith(path),
  );
}

export function isAuthPage(pathname: string): boolean {
  return AUTH_ROUTES_LIST.some((route) => pathname.startsWith(route));
}

export function isPublicPage(pathname: string): boolean {
  return PUBLIC_PAGES.some((path) => pathname.startsWith(path));
}

export function isRootPage(pathname: string): boolean {
  return pathname === APP_ROUTES.APP.ROOT;
}

export function getDefaultRouteForUser(profile?: Profile | null): string {
  if (!profile) return APP_ROUTES.AUTH.SIGN_IN;

  if (isAdminUser(profile)) {
    return APP_ROUTES.ADMIN.ROOT;
  }

  if (isAuthenticatorUser(profile)) {
    return APP_ROUTES.AUTHENTICATOR.PROFILE;
  }

  return APP_ROUTES.PROFILE;
}

