import { withAuth } from "next-auth/middleware";
import { NextResponse } from "next/server";

import { calculateExpiresIn } from "@/shared/lib/auth";
import { APP_ROUTES } from "./src/shared/config/app-routes";
import {
  getDefaultRouteForUser,
  isAdminRoute,
  isAdminUser,
  isAuthenticatorRoute,
  isAuthenticatorUser,
  isAuthPage,
  isProtectedRoute,
  isPublicPage,
  isRootPage,
} from "./src/shared/config/rbac-constants";

export default withAuth(
  function middleware(req) {
    const { pathname } = req.nextUrl;
    const token = req.nextauth.token;

    const isAuthRoute = isAuthPage(pathname);
    const isAuthenticated = !!token?.accessToken;
    const userProfile = token?.profile;
    const hasTemporaryPassword = token?.isTemporaryPassword;

    if (
      hasTemporaryPassword &&
      pathname !== APP_ROUTES.AUTH.CHANGE_TEMP_PASSWORD
    ) {
      return NextResponse.redirect(
        new URL(APP_ROUTES.AUTH.CHANGE_TEMP_PASSWORD, req.url),
      );
    }

    if (isAuthRoute && isAuthenticated) {
      const defaultRoute = getDefaultRouteForUser(userProfile);

      return NextResponse.redirect(new URL(defaultRoute, req.url));
    }

    if (isAdminRoute(pathname) && !isAdminUser(userProfile)) {
      const defaultRoute = getDefaultRouteForUser(userProfile);

      return NextResponse.redirect(new URL(defaultRoute, req.url));
    }

    if (isAuthenticatorRoute(pathname) && !isAuthenticatorUser(userProfile)) {
      const defaultRoute = getDefaultRouteForUser(userProfile);

      return NextResponse.redirect(new URL(defaultRoute, req.url));
    }

    if (
      isProtectedRoute(pathname) &&
      (isAdminUser(userProfile) || isAuthenticatorUser(userProfile))
    ) {
      const defaultRoute = getDefaultRouteForUser(userProfile);

      return NextResponse.redirect(new URL(defaultRoute, req.url));
    }

    return NextResponse.next();
  },
  {
    callbacks: {
      authorized: ({ token, req }) => {
        const { pathname } = req.nextUrl;

        if (
          isAuthPage(pathname) ||
          isPublicPage(pathname) ||
          isRootPage(pathname) ||
          token?.isTemporaryPassword
        )
          return true;

        const expiresIn = calculateExpiresIn(token?.accessToken);
        const refreshTokenIsExpired =
          token?.refreshTokenExpiresAt &&
          token?.refreshTokenExpiresAt < Date.now();

        if (expiresIn <= 30 && refreshTokenIsExpired) {
          return false;
        }

        return !!token;
      },
    },
    pages: {
      signIn: APP_ROUTES.AUTH.SIGN_IN,
      signOut: APP_ROUTES.AUTH.SIGN_IN,
    },
  },
);

export const config = {
  matcher: [
    "/((?!_next/static|_next/image|favicon.ico|.*\\.(?:svg|png|jpg|jpeg|gif|webp|ico|mp4|webm)|api|design).*)",
  ],
};

