"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import { signIn } from "next-auth/react";
import Link from "next/link";
import { useState } from "react";
import { useForm } from "react-hook-form";
import { z } from "zod";

import { APP_ROUTES } from "@/shared/config/app-routes";
import { Form } from "@/shared/ui/form/form";
import { FormControl } from "@/shared/ui/form/form-control";
import { FormField } from "@/shared/ui/form/form-field";
import { FormItem } from "@/shared/ui/form/form-item";
import { FormLabel } from "@/shared/ui/form/form-label";
import { FormMessage } from "@/shared/ui/form/form-message";
import { Input } from "@/shared/ui/input";
import { toast } from "@/shared/ui/notification";
import { PasswordInput } from "@/shared/ui/password-input";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/shared/ui/shadcn/dialog";

const signInSchema = z.object({
  email: z.string().email("Please enter a valid email"),
  password: z.string().min(1, "Password is required"),
});

type SignInFormData = z.infer<typeof signInSchema>;

interface BuybackSignInModalProps {
  open: boolean;
  onClose: () => void;
}

export function BuybackSignInModal({ open, onClose }: BuybackSignInModalProps) {
  const [isLoading, setIsLoading] = useState(false);

  const form = useForm<SignInFormData>({
    resolver: zodResolver(signInSchema),
    defaultValues: { email: "", password: "" },
  });

  const onSubmit = async (data: SignInFormData) => {
    setIsLoading(true);
    try {
      const result = await signIn("credentials", {
        email: data.email,
        password: data.password,
        redirect: false,
      });

      if (result?.error) {
        toast.error("Sign In Failed", {
          description: "Invalid email or password",
        });
        return;
      }

      if (result?.ok) {
        onClose();
      }
    } catch {
      toast.error("Sign In Failed", {
        description: "An unexpected error occurred",
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={(isOpen) => !isOpen && onClose()}>
      <DialogContent className="max-w-md bg-[#F5F3EF]">
        <DialogHeader>
          <DialogTitle className="font-light font-new-serif text-2xl text-[#44403C] leading-[120%]">
            Sign in to submit your offer
          </DialogTitle>
          <p className="font-new-sans text-[#44403C] text-sm leading-[150%]">
            Your progress has been saved. Sign in to complete your submission.
          </p>
        </DialogHeader>

        <Form {...form}>
          <form
            onSubmit={form.handleSubmit(onSubmit)}
            className="flex flex-col gap-4"
          >
            <FormField
              control={form.control}
              name="email"
              render={({ field }) => (
                <FormItem>
                  <FormLabel className="font-new-sans font-normal text-[#44403C] text-sm">
                    Email
                  </FormLabel>
                  <FormControl>
                    <Input
                      placeholder="Enter your email"
                      type="email"
                      className="h-12 rounded-[4px] border-[#A8A29E] bg-white px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E]"
                      {...field}
                    />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            <FormField
              control={form.control}
              name="password"
              render={({ field }) => (
                <FormItem>
                  <FormLabel className="font-new-sans font-normal text-[#44403C] text-sm">
                    Password
                  </FormLabel>
                  <FormControl>
                    <PasswordInput
                      placeholder="Enter your password"
                      containerClassName="h-12 rounded-[4px] border-[#A8A29E] bg-white px-3"
                      className="font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E]"
                      {...field}
                    />
                  </FormControl>
                  <div className="flex justify-end">
                    <Link
                      href={APP_ROUTES.AUTH.REQUEST_FORGOT_PASSWORD}
                      className="font-new-sans text-[#000944] text-xs transition-opacity hover:opacity-70"
                    >
                      Forgot Password
                    </Link>
                  </div>
                  <FormMessage />
                </FormItem>
              )}
            />

            <button
              type="submit"
              disabled={isLoading}
              className="flex h-12 w-full items-center justify-center rounded-[4px] bg-[#021171] font-medium font-new-sans text-[#F5F3EF] text-base transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-70"
            >
              {isLoading ? "Signing In..." : "Sign In & Submit"}
            </button>

            <p className="text-center font-new-sans text-[#44403C] text-sm leading-[150%]">
              New to LuxFlow?{" "}
              <Link
                href={APP_ROUTES.AUTH.SIGN_UP}
                className="font-semibold text-[#44403C] hover:opacity-70"
              >
                Create an Account
              </Link>
            </p>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

