// ---------------------------------------------------------------------------
// Hero headline — word-by-word reveal
// ---------------------------------------------------------------------------
function AnimatedHeadline({
  text,
  className,
}: {
  text: string;
  className?: string;
}) {
  const words = text.split(" ");
  return (
    <motion.h1
      animate="visible"
      className={className}
      initial="hidden"
      variants={staggerContainer}
    >
      {words.map((word, idx) => (
        <motion.span
          // eslint-disable-next-line react/no-array-index-key
          className="inline-block"
          key={`word-${idx}`}
          variants={{
            hidden: { opacity: 0, y: 40, rotateX: -15 },
            visible: {
              opacity: 1,
              y: 0,
              rotateX: 0,
              transition: { duration: 0.7, ease: [0.22, 1, 0.36, 1] },
            },
          }}
        >
          {word}
          {idx < words.length - 1 ? "\u00A0" : ""}
        </motion.span>
      ))}
    </motion.h1>
  );
}

// ---------------------------------------------------------------------------
// Steps section — Lottie + synced progress bars
// ---------------------------------------------------------------------------
function StepsSection({ ctaHref }: { ctaHref: string | undefined }) {
  const router = useRouter();
  const [activeStep, setActiveStep] = useState(0);
  const [liveProgress, setLiveProgress] = useState(0);
  const activeStepRef = useRef(0);

  const handleDotLottieRef = useCallback((dl: DotLottie | null) => {
    if (!dl) return;

    dl.addEventListener("frame", () => {
      if (dl.totalFrames > 0) {
        setLiveProgress(dl.currentFrame / dl.totalFrames);
      }
    });

    dl.addEventListener("complete", () => {
      const next = (activeStepRef.current + 1) % 4;
      activeStepRef.current = next;
      setActiveStep(next);
      setLiveProgress(0);
    });
  }, []);

  return (
    <section className="overflow-hidden bg-background">
      <div className="flex flex-col min-[1172px]:flex-row min-[1172px]:items-stretch">
        {/* Left — dark damask panel with iPhone */}
        <div className="relative flex items-center justify-center overflow-hidden bg-[#020A3A] px-6 py-16 min-[1172px]:w-[50%] min-[1172px]:shrink-0 min-[1172px]:py-24">
          {/* Damask background image */}
          <Image
            alt="Steps background"
            aria-hidden="true"
            className="pointer-events-none object-cover opacity-60"
            fill
            sizes="50vw"
            src="/new-design-images/steps-bg.webp"
          />
          {/* Lottie inside iPhone mockup */}
          <motion.div
            className="relative z-10"
            initial="hidden"
            variants={slideLeft}
            viewport={VP}
            whileInView="visible"
          >
            <div
              className="relative w-[240px] min-[1172px]:w-[320px]"
              style={{ aspectRatio: "740 / 1500" }}
            >
              {/* Lottie clipped to screen — overflow-hidden + rounded clips corners & background */}
              <div className="absolute inset-[2%_4%] overflow-hidden rounded-[12%]">
                <DotLottieReact
                  autoplay
                  dotLottieRefCallback={handleDotLottieRef}
                  key={activeStep}
                  loop={false}
                  src={`/lottie/Scene-${activeStep + 1}.lottie`}
                  style={{ width: "100%", height: "100%" }}
                />
              </div>
              {/* iPhone frame on top */}
              <Image
                alt="LuxFlow mobile app"
                className="pointer-events-none z-10 object-contain"
                fill
                sizes="320px"
                src="/new-design-images/iphone-mockup.png"
              />
            </div>
          </motion.div>
        </div>

        {/* Right — steps list */}
        <div className="flex flex-1 flex-col gap-8 bg-[#F5F3EF] px-10 py-16">
          <motion.h2
            className="font-extralight font-new-serif text-3xl leading-[1.2] min-[1172px]:text-[44px]"
            initial="hidden"
            variants={fadeUp}
            viewport={VP}
            whileInView="visible"
          >
            Get Instant Cash
            <br />
            in 4 Simple Steps
          </motion.h2>

          <div className="flex flex-col">
            {LANDING_STEPS.map((step, index) => {
              let barWidth = "0%";
              if (index < activeStep) {
                barWidth = "100%";
              } else if (index === activeStep) {
                barWidth = `${liveProgress * 100}%`;
              }

              return (
                <motion.div
                  className="flex flex-col gap-3 border-[#D6D3D1] border-t py-5 first:border-t-0 first:pt-0"
                  initial="hidden"
                  key={step.number}
                  transition={{ delay: index * 0.08 }}
                  variants={fadeUp}
                  viewport={VP}
                  whileInView="visible"
                >
                  <div className="flex items-start justify-between gap-4">
                    <h3
                      className={
                        "font-extralight font-new-serif text-[24px] leading-[1.2] transition-colors min-[1172px]:text-[30px]"
                      }
                    >
                      {index + 1}. {step.title}
                    </h3>
                  </div>
                  <p className="font-new-sans text-sm leading-relaxed">
                    {step.description}
                  </p>
                  {/* Progress bar — driven by Lottie frame*/}
                  <div className="relative h-[2px] w-full overflow-hidden bg-[#D6D3D1]">
                    <div
                      className="absolute inset-y-0 left-0 bg-[#001A8C] transition-none"
                      style={{ width: barWidth }}
                    />
                  </div>
                </motion.div>
              );
            })}
          </div>

          {ctaHref ? (
            <motion.div
              className="w-fit"
              initial="hidden"
              variants={fadeUp}
              viewport={VP}
              whileHover={{ scale: 1.03 }}
              whileInView="visible"
              whileTap={{ scale: 0.97 }}
            >
              <Button
                className="rounded-sm"
                onClick={() => {
                  router.push(ctaHref);
                }}
              >
                Start with a Quote
                <span aria-hidden="true">→</span>
              </Button>
            </motion.div>
          ) : null}
        </div>
      </div>
    </section>
  );
}

